const res = $input.first().json;
const vars = $('Inject Vars').first().json;
const headers = res.headers ?? {};

const rawSetCookie = headers['set-cookie'] ?? headers['Set-Cookie'] ?? '';
const merged = Array.isArray(rawSetCookie) ? rawSetCookie.join(';') : String(rawSetCookie);

let sid = (merged.match(/(?:^|;\s*)session_id=([^;]+)/)?.[1] || '');
sid = sid
  .replace(/[\r\n\t ]+/g, '')
  .replace(/^session_id=/i, '')
  .replace(/[^A-Za-z0-9._\-+/=]/g, '')
  .trim();

if (!sid) throw new Error('session_id vacío tras limpieza');

return [{ json: { ...vars, session_id: sid, cookie_header: `session_id=${sid}` } }];

const brandData = [
  { name:'koldcup',       ig:'17841466499415339', fb:'61559153273449',   odoo_id:38, node:'IG koldcup' },
  { name:'koldworld',     ig:'17841478500163339', fb:'885658441291968',  odoo_id:37, node:'IG koldworld' },
  { name:'koldhome',      ig:'17841480705102602', fb:'976588825542989',  odoo_id:36, node:'IG koldhome' },
  { name:'koldsnack',     ig:'17841480237269261', fb:'994376280421827',  odoo_id:35, node:'IG koldsnack' },
  { name:'koldhielomx',   ig:'17841480531411885', fb:'918436421361412',  odoo_id:34, node:'IG koldhielomx' },
  { name:'koldsmuthiemx', ig:'17841478135575883', fb:'891669537374121',  odoo_id:33, node:'IG koldsmuthiemx' }
];

const cutoff = new Date(Date.now() - 12 * 60 * 60 * 1000);
const sid = $('Extract SID').first().json;
const vars = $('Inject Vars').first().json;

const allPosts = [];

for (const brand of brandData) {
  let posts = [];
  try {
    const raw = $('Merge Posts').first().json[brand.name] || $node[brand.node]?.json;
    if (!raw) {
        // Fallback for node ref
        const rawFallback = $items(brand.node)[0]?.json;
        if (rawFallback) posts = rawFallback.data || [];
    } else {
        posts = raw.data || [];
    }
  } catch(e) { continue; }

  for (const post of posts) {
    const postDate = new Date(post.timestamp);
    if (postDate < cutoff) continue;
    if ((post.comments_count || 0) === 0) continue;

    allPosts.push({ json: {
      post_id: post.id,
      brand: brand.name,
      brand_odoo_id: brand.odoo_id,
      ig_account: brand.ig,
      fb_page: brand.fb,
      post_caption: (post.caption || '').substring(0, 200),
      post_date: post.timestamp,
      comments_count: post.comments_count,
      session_id: sid.session_id,
      cookie_header: sid.cookie_header,
      ...vars
    }});
  }
}

if (allPosts.length === 0) {
  return [{ json: { nothing_to_scan: true, ...vars }}];
}

return allPosts;

const raw = $input.first().json;
const comments = raw.data || raw.result?.data || [];
const ctx = $('Build Comments Query').first().json;

if (comments.length === 0) {
  return [{ json: { no_comments: true, brand: ctx.brand }}];
}

const batch = comments.slice(0, 20).map(c => ({
  id: c.id,
  msg: (c.message || '').substring(0, 300),
  from: c.from?.name || c.from?.username || 'anónimo',
  from_id: c.from?.id || '',
  timestamp: c.timestamp,
  likes: c.like_count || 0
}));

return [{ json: {
  comments_batch: batch,
  total_comments: comments.length,
  post_id: ctx.post_id,
  brand: ctx.brand,
  brand_odoo_id: ctx.brand_odoo_id,
  post_caption: ctx.post_caption,
  ig_account: ctx.ig_account,
  session_id: ctx.session_id,
  cookie_header: ctx.cookie_header,
  openai_key: ctx.openai_key,
  wa_token: ctx.wa_token,
  wa_phone_id: ctx.wa_phone_id,
  sales_wa: ctx.sales_wa,
  odoo_url: ctx.odoo_url,
  meta_token: ctx.meta_token,
  no_comments: false
}}];

const raw = $json.choices[0].message.content;
const gpt = typeof raw === 'string' ? JSON.parse(raw) : raw;
const signals = (gpt.signals || []).filter(s =>
  s.retail_intent === true && s.confidence >= 0.70
);

const ctx = $('Parse Comments').first().json;
const sid = { session_id: ctx.session_id, cookie_header: ctx.cookie_header };
const vars = {
  wa_token: ctx.wa_token,
  wa_phone_id: ctx.wa_phone_id,
  sales_wa: ctx.sales_wa,
  odoo_url: ctx.odoo_url,
  meta_token: ctx.meta_token,
  openai_key: ctx.openai_key
};

if (signals.length === 0) {
  return [{ json: { no_signals: true, brand: ctx.brand }}];
}

return signals.map(s => ({ json: {
  comment_id: s.comment_id,
  brand: ctx.brand,
  brand_odoo_id: ctx.brand_odoo_id,
  post_id: ctx.post_id,
  post_caption: ctx.post_caption,
  ig_account: ctx.ig_account,
  retail_intent: s.retail_intent,
  confidence: s.confidence,
  intent_type: s.intent_type || 'mayoreo',
  zona_mencionada: s.zona_mencionada || null,
  from_name: s.from_name || '',
  from_id: s.from_id || '',
  message: s.message || '',
  comment_timestamp: s.timestamp,
  razon: s.razon || '',
  no_signals: false,
  ...sid,
  ...vars
}}));

return [{ json: {
  payload: {
    jsonrpc: "2.0", method: "call",
    params: {
      model: "x_kold_retail_signal_event",
      method: "search_read",
      args: [[["x_comment_id", "=", $json.comment_id]]],
      kwargs: { fields: ["id"], limit: 1 }
    }
  },
  ...($json)
}}];

const result = $input.first().json.result || [];
const ctx = $('Build Dedup Check').first().json; // Context preserve across batch

if (result.length > 0) {
  return [{ json: { is_duplicate: true, comment_id: ctx.comment_id }}];
}
return [{ json: { is_duplicate: false, ...ctx }}];

const ctx = $input.first().json;
const now = new Date().toISOString().replace('T',' ').substring(0,19);
// fallback robust text length limit or parsing
return [{ json: {
  signal_payload: {
    jsonrpc: "2.0", method: "call",
    params: {
      model: "x_kold_retail_signal_event", method: "create",
      args: [[{
        x_name: `Señal Retail — ${ctx.brand} — ${ctx.from_name || 'anónimo'}`,
        x_brand_id: String(ctx.brand_odoo_id),
        x_comment_id: ctx.comment_id,
        x_post_id: ctx.post_id,
        x_from: ctx.from_id || '',
        x_from_name: ctx.from_name || '',
        x_body: ctx.message,
        x_intent_type: ctx.intent_type,
        x_confidence: parseFloat(ctx.confidence),
        x_zona: ctx.zona_mencionada || '',
        x_platform: 'instagram',
        x_source: 'instagram',
        x_received_at: ctx.comment_timestamp || now,
        x_status: 'nuevo'
      }]],
      kwargs: {}
    }
  },
  ...ctx
}}];

const ctx = $('Build Signal Record').first().json;
const signalId = $input.first().json.result || 0;

const zona = ctx.zona_mencionada
  ? ` — Zona: ${ctx.zona_mencionada}` : '';
const typeMap = {
  'mayoreo': 'Interés Mayoreo',
  'distribucion': 'Busca Distribución',
  'zona_nueva': 'Nueva Zona',
  'precio_reventa': 'Precio Reventa',
  'otro': 'Señal Retail'
};
const tipo = typeMap[ctx.intent_type] || 'Señal Retail';

return [{ json: {
  lead_payload: {
    jsonrpc: "2.0", method: "call",
    params: {
      model: "crm.lead", method: "create",
      args: [[{
        name: `${tipo} — ${ctx.brand}${zona} — @${ctx.from_name}`,
        contact_name: ctx.from_name || '',
        description:
          `📱 Comentario en Instagram (${ctx.brand})\n` +
          `Post: ${ctx.post_caption}\n\n` +
          `Comentario: ${ctx.message}\n\n` +
          `Intent: ${ctx.intent_type} (confianza: ${Math.round(ctx.confidence*100)}%)\n` +
          `Zona mencionada: ${ctx.zona_mencionada || 'No especificada'}\n` +
          `Razón IA: ${ctx.razon}`,
        x_source_channel: 'instagram',
        x_social_uid: ctx.from_id || '',
        tag_ids: [[4, 1]], // The tag 'Retail Signal' has ID: 1 as created in previous step
        priority: ctx.confidence >= 0.90 ? '2' : '1'
      }]],
      kwargs: {}
    }
  },
  signal_id: signalId,
  ...ctx
}}];

const leadId = $input.first().json.result || 0;
const ctx = $('Build CRM Lead').first().json;

return [{ json: {
  payload: {
    jsonrpc: "2.0", method: "call",
    params: {
      model: "x_kold_retail_signal_event",
      method: "write",
      args: [
        [parseInt(ctx.signal_id)],
        { x_lead_id: leadId, x_status: 'lead_creado' }
      ],
      kwargs: {}
    }
  },
  lead_id: leadId,
  ...ctx
}}];

const ctx = $('Build CRM Lead').first().json;
const leadId = $('Link Lead to Signal').first().json.lead_id;

const tipoLabel = {
  'mayoreo': '🏪 Interés en mayoreo',
  'distribucion': '🚚 Busca distribución',
  'zona_nueva': '📍 Nueva zona sin cobertura',
  'precio_reventa': '💰 Precio para reventa',
  'otro': '📊 Señal retail'
}[ctx.intent_type] || '📊 Señal retail';

const zonaMsg = ctx.zona_mencionada
  ? `\n📍 Zona mencionada: *${ctx.zona_mencionada}*` : '';

const msg =
  `🎯 *Nueva Señal Retail — ${ctx.brand}*\n\n` +
  `${tipoLabel}\n` +
  `👤 Usuario: @${ctx.from_name || 'anónimo'}${zonaMsg}\n` +
  `💬 Comentario: "${ctx.message}"\n` +
  `🤖 Confianza IA: ${Math.round(ctx.confidence*100)}%\n\n` +
  `📌 Post: "${ctx.post_caption}"\n\n` +
  `Lead creado en Odoo: ${ctx.odoo_url}/web#id=${leadId}&model=crm.lead\n\n` +
  `Responde al comentario en IG o contacta directamente.`;

let formattedPhone = (ctx.sales_wa || '').replace(/\D/g, '');
if (formattedPhone.length === 10) formattedPhone = '52' + formattedPhone;

return [{ json: {
  wa_body: msg,
  wa_to: formattedPhone,
  wa_token: ctx.wa_token,
  wa_phone_id: ctx.wa_phone_id,
  odoo_url: ctx.odoo_url,
  cookie_header: ctx.cookie_header,
  comment_id: ctx.comment_id
}}];

return [{
  json: {
    log_payload: {
      jsonrpc: "2.0", method: "call",
      params: {
        model: "x_kold_workflow_run_log", method: "create",
        args: [[{
          x_workflow_id: "W08",
          x_run_id: "W08_" + $json.comment_id,
          x_status: "success",
          x_started_at: new Date().toISOString().replace('T', ' ').substring(0, 19),
          x_environment: "staging"
        }]],
        kwargs: {}
      }
    },
    ...$json
  }
}];

return [{ json: { payload: {
  x_workflow_id: "W08 Retail Signal",
  x_run_id: "W08_ERROR_" + Date.now().toString(),
  x_status: "fail",
  x_error_message: $json.execution?.error?.message || "Error desconocido",
  x_started_at: new Date().toISOString().replace('T',' ').substring(0,19),
  x_environment: "staging"
}}}];
